from pathlib import Path
import re
from collections import defaultdict
root = Path('shaders/escape_time_family/experimental_named')
func_re = re.compile(r'^\s*(?:vec[234]|float|int|bool)\s+([A-Za-z_]\w*)\s*\(')
by_func = defaultdict(list)
for path in sorted(root.rglob('*.frag')):
    text = path.read_text(encoding='utf-8')
    funcs = sorted(set(func_re.findall(text)))
    for fn in funcs:
        by_func[fn].append(str(path.relative_to(root)))
for fn, paths in sorted(by_func.items()):
    if len(paths) >= 2:
        print(f'{fn}: {len(paths)} files')
        for path in paths[:10]:
            print(f'  - {path}')
        if len(paths) > 10:
            print(f'  ... {len(paths)-10} more')
